    if (stateKey !== lastSavedStateRef.current) {
      lastSavedStateRef.current = stateKey;

      if (immediate) {
        if (debouncedSaveTimeoutRef.current) {
          clearTimeout(debouncedSaveTimeoutRef.current);
          debouncedSaveTimeoutRef.current = null;
        }
        if (backendHttpUrl) {
