            }
          }
          // Preserve the mode if it was already set and not being overwritten
          const mode = updatedFields.mode !== undefined ? updatedFields.mode : s.mode || "";
          const updatedSession = { ...s, ...updatedFields, title, mode };

          saveIfChanged(updatedSession, immediate);

