* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background-color: var(--bg-color);
  color: var(--text-main);
  background-image: var(--bg-radial-glow);
  background-attachment: fixed;
  min-height: 100vh;
  overflow: hidden;
  font-feature-settings: "cv02", "cv03", "cv04", "cv11";
}

